async (page) => {
  // Continue navigating west to Bubba at (121, 231)
  // Take incremental hops within visible range
  for (let attempt = 0; attempt < 4; attempt++) {
    const pos = await page.evaluate(() => window.__latestGameState.player_position);
    const asciiMap = await page.evaluate(() => window.__latestAsciiMap);

    if (!asciiMap || asciiMap.error) break;

    // Target: x=121, y=231. Go west and slightly south
    const targetX = Math.max(pos.x - 12, 121);
    const targetY = Math.min(pos.y + 4, 231);

    const result = await page.evaluate(({x, y}) => JSON.stringify(window.__clickTile(x, y)), {x: targetX, y: targetY});
    await page.waitForTimeout(3000);

    const newPos = await page.evaluate(() => window.__latestGameState.player_position);
    if (newPos.x <= 125) break; // close enough to Bubba
  }

  const state = await page.evaluate(() => {
    const s = window.__latestGameState;
    const bubba = s.nearby_entities.find(e => e.name === 'Bubba');
    return JSON.stringify({pos: s.player_position, hp: s.player_stats, bubba: bubba ? {dist: bubba.distance, on_screen: bubba.on_screen, cx: bubba.click_x, cy: bubba.click_y} : null});
  });
  return state;
}
